	}
	(*dest_mgr->finish_output)(&cinfo, dest_mgr);

	/* Complete the decompression process. */
	JAS_DBGLOG(10, ("jpeg_finish_decompress(%p)\n", &cinfo));
	jpeg_finish_decompress(&cinfo);

